import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"0.灵丹总纲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/灵丹/0.灵丹总纲.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/灵丹/0.灵丹总纲.md"}'),o={name:"4.资源分区/7.物品与装备/9.消耗品/6.系列消耗品/灵丹/0.灵丹总纲.md"};function _(d,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_0-灵丹总纲",tabindex:"-1"},[p("0.灵丹总纲 "),e("a",{class:"header-anchor",href:"#_0-灵丹总纲","aria-label":'Permalink to "0.灵丹总纲"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),s('<h1 id="_0-灵丹总纲-1" tabindex="-1">0.灵丹总纲 <a class="header-anchor" href="#_0-灵丹总纲-1" aria-label="Permalink to &quot;0.灵丹总纲&quot;">​</a></h1><p>灵丹总纲</p><p>灵丹，即修仙、高武世界中常见的或用于辅助修炼，或具有神奇功效的消耗物品，炼丹师也是此类世界中常见的职业。</p><p>一般而言，灵丹的功效根据其使用世界的灵气浓郁程度决定，毫无灵气的现代世界使用它的原本药效，处于修仙世界中时，这个药效将使用修仙世界药效。</p><p>炼制丹药：<br> 炼制丹药的前提是具有炼丹器具，它可以是“道士”下属中的【从火炉灰】，也可以是命运编织者中的“方士”。当然，如果没有这些强化，也可以在主神处以50分的价格买一尊便携炼丹炉，当然，这不意味着可以在影片中炼丹，除非有对应的强化能力。</p><p>获取丹药：<br> 获取丹药有两种途径，其一为购买获得，其二为炼制获得，直接购买丹药需花费对应标注的价格，而炼制丹药在拥有器具的基础上，还需要如同造物一般先花费某种需要炼制的丹药总价格7成的价格购买原料，并进行一次造物检定，若造物成功，则获得一颗炼制而成的丹药。</p><p>品级与异变：<br> 丹药具有凡品、下品、中品、上品、仙品、道品从低到高六个等级，分别对应E-D-C-B-A-S级，但其中B、A、S级丹谱遗失，暂时无法购买或炼制。炼丹者的最高内在支线等级低于需要炼制的丹药等级时，造物难度将加一级计算，服用丹药者的最高内在支线等级低于服用的丹药等级时，服用后持续生效的轮次将减半。某些丹药具有它的异变丹种，在炼制这些丹药的普通版本时，投一次自然十面骰，出目为8、9、10时，改为炼制出异变版本。</p><p>服用丹药与造化已尽：<br> 一般而言，同时服用多颗生效时间非永久的同一种丹药只生效其中一个，异变版本和普通版本视为同一种，在服用时，可以将丹药含于口中，支付等同于该丹药品质等级*2点东方通用能量，将其药力暂时封存，封存的药力最多不能超过封存者的最高内在支线等级*3天（D1C2B3A4S5）。特殊的，若某种丹药提供的效果为永久效果，则其会特殊标注【造化已尽】的次数，代表服用规定次数的该丹药后，再服用更多的该种丹药也无法获得更多增益。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(o,[["render",_]]);export{f as __pageData,m as default};
